  stage: string
  summary?: string
  created_at: string
  trust_state: ArtifactTrustState
  superseded_at?: string
  superseded_by?: string
  supersession_reason?: string
}

export type ArtifactRegistryEntry = Artifact & { ticket_id: string }

export type Ticket = {
  id: string
